def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 2:
            priorities[i] = ratio ** 4 + np.log(bin_capacity + 1)
        elif 1 < ratio <= 2:
            priorities[i] = (ratio ** 3) * np.exp(-bin_capacity / (item + 1))
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 6):
                term = ((1 - ratio) ** j) / j
                if j % 2 == 0:
                    term *= 1.2
                else:
                    term *= 0.8
                score += term
            if bin_capacity < item * 1.5:
                score *= 2
            elif bin_capacity < item * 3:
                score *= 1.2
            else:
                for k in range(1, 4):
                    score += ((bin_capacity / (item + k)) ** 0.5) / (k * 10)
            priorities[i] = score
    for idx in range(len(priorities)):
        if priorities[idx] < 0:
            priorities[idx] = 0
    return priorities
